                <svg viewBox="0 0 16 16" className="w-4 h-4 fill-none stroke-[#a16207]" strokeWidth="1.5"><circle cx="8" cy="8" r="6"/><path d="M5.5 10.5h5M6 6.5v.01M10 6.5v.01" strokeLinecap="round"/></svg>
